    (1, "不穿全套兽装，如果仅仅佩戴一个兽耳发箍和一条尾巴，这类装扮在二次元偏向哪种属性，而不是硬核Furry？", ["机甲控", "兽耳娘/兽娘 (Kemonomimi)", "硬核Furry", "肌肉控"], "B", 2, "Furry强调动物保留兽脸肌理比例，而兽耳娘主体依然完全是人类。", ["Furry", "兽耳"]),
    (1, "在推特或画师平台上，专门接受其他兽迷委托有偿绘制他们设定的行为称为？", ["讨饭", "接稿 / 约稿 (Commission)", "化缘", "走穴"], "B", 1, "Furry圈的画师通过接稿形成了庞大成熟的同人经济圈。", ["Furry", "Commission"]),
    (2, "Furry兽装的风格根据头骨材质和眼睛设计主要可以分为哪几种典型风格？", ["卡通/动漫风 (Toony)", "写实风 (Realistic)", "半卡通风 (Semi-toony)", "隐形风"], "ABC", 2, "卡通风有巨大的2D眼睛，写实风则采用树脂假眼并且有极强的拟真毛发和牙齿。", ["Furry", "兽装风格"]),
    (1, "Furry圈对别人毛茸茸的毛皮设定常常产生触觉上的向往，衍生出一个喜爱抚摸、拥抱的特有圈内行为叫？", ["毛聚", "吸毛 / 抱抱", "剃毛", "剪毛"], "B", 1, "展会上常有提供Free Hug的兽装表演者。", ["Furry", "行为"]),
    (1, "由于Fursuit内部极其闷热，兽装扮演者必不可少的维持生命体征的隐藏装备通常是？", ["背着氧气面罩", "头骨内安装的微型排风小风扇", "内置微波炉", "全身静脉注射降温"], "B", 2, "大多数兽头的嘴部或鼻子内部会暗藏散热风扇。", ["Furry", "兽装制作"]),
    (1, "以拟人化高中动物角色为班底的著名悬疑群像题材漫画/动画作品是？", ["《疯狂动物城》", "《动物狂想曲 / BEASTARS》", "《猫和老鼠》", "《喜羊羊与灰太狼》"], "B", 1, "BEASTARS深刻探讨了肉食与草食拟人动物间的社会伦理，在圈内大热。", ["Furry", "作品"]),

    # 7. Speedrunning (速通) (10 questions)
    (1, "在电子游戏速通（Speedrun）中，分类为“Any%”意思是？", ["必须杀死所有敌人", "只要能最快通关即可，不限制完成度及跳关", "100%全收集通关", "必须0杀敌通关"], "B", 1, "Any%是追求极限通关时间的最热门且破坏游戏最严重的跑法。", ["速通", "Any%"]),
    (2, "速通分类中“100%”跑法通常要求玩家做到哪些？", ["获得所有的收集品", "完成所有主线和支线任务", "解锁所有能力", "跳入虚空直接触发结局"], "ABC", 1, "100%通关要求按游戏内定义的满完成度来通关，极其考验规划路线。", ["速通", "100%"]),
    (1, "在速通中利用游戏的漏洞或代码缺陷直接穿墙、跳跃大段流程的技巧统称为？", ["外挂", "Glitches (卡Bug / 邪道)", "MOD", "修改器"], "B", 1, "Glitches是速通文化的重要核心之一，许多速通是在欣赏代码毁灭的艺术。", ["速通", "Glitches"]),
    (1, "TAS速通 (Tool-Assisted Speedrun) 是指什么？", ["找代练帮忙通关", "用物理工具按键盘", "利用模拟器和逐帧输入工具，达到人类手速难以企及的无失误极限通关", "通过打电话向开发者求助"], "C", 1, "TAS通过录制脚本创造理论极限，更像是一种科研而非人工竞技。", ["速通", "TAS"]),
    (1, "利用游戏内存溢出漏洞或特定操作，将某些物品的代码强行改为结局通关触发器，此类极其硬核的底层邪道手法通常被称为？", ["暴力破解", "内存操纵 / 任意代码执行 (ACE)", "游戏重置", "锁血"], "B", 3, "ACE(Arbitrary Code Execution) 是部分老游戏Any%速通里的终极武器（如宝可梦、马里奥）。", ["速通", "ACE"]),
    (2, "著名的每年举办两次，为慈善组织筹款的全球最大速通大会是？", ["SGDQ (Summer Games Done Quick)", "AGDQ (Awesome Games Done Quick)", "E3", "TGA"], "AB", 1, "GDQ系列活动是世界速通选手的盛大派对。", ["速通", "GDQ"]),
    (1, "“OOB”是速通中频繁出现的一个术语缩写，它的全称是？", ["Out Of Bounds (出界/穿墙)", "Only One Button", "On Our Back", "Over Over Bang"], "A", 2, "进入OOB就能无视原本的空气墙和房间阻挡。", ["速通", "OOB"]),
    (1, "如果速通类别标明了“Glitchless”，意味着玩家在通关过程中？", ["必须使用所有的Bug", "禁止使用任何Bug漏洞和邪道，必须按开发者预期的正常途径通关", "没有时间限制", "必须闭着眼睛打"], "B", 1, "这属于“正常游玩的最快速”挑战。", ["速通", "Glitchless"]),
    (1, "某些游戏由于RNG（随机数生成器）极大地影响通关速度，速通玩家会通过特定复杂的开局输入来操控随机结果，这被称为？", ["背板", "乱数操作 (RNG Manipulation)", "黑客入侵", "修改器"], "B", 2, "通过背下极其复杂的微操让系统生成特定的怪物掉落或暴击。", ["速通", "RNG"]),
    (1, "速通排行榜平台最权威的全球数据库网站是？", ["Twitch", "Speedrun.com", "IGN", "Steam"], "B", 1, "几乎所有游戏的速通世界纪录审核和排行都在此网站记录。", ["速通", "网站"]),

    # 8. 业余无线电 (Ham Radio) & EDC (10 questions)
    (1, "业余无线电爱好者的通用英文绰号是？", ["Geek", "Ham (火腿)", "Hacker", "Nerd"], "B", 1, "全世界的业余无线电爱好者都骄傲地自称为火腿(Ham)。", ["无线电", "Ham"]),
    (2, "在中国想要合法操作发射业余无线电台（对讲机），必须具备哪两项手续文件？", ["电台设备购买小票", "电台执照 (电台执照)", "$操作证 (中国无线电协会颁发)$", "$播音员主持人证$"], "BC", 2, "必须人有操作证、机有电台执照（人机双证），否则就是非法的“黑飞/黑电台”。", ["无线电", "法规"]),
    (1, "业余无线电中，用来代表呼叫者的唯一全球识别代码（如BG1XXX）称为？", ["IP地址", "呼号 (Call Sign)", "手机号", "密码"], "B", 1, "呼号由各国家无线电管理机构分配，前缀代表国家和地区。", ["无线电", "呼号"]),
    (1, "火腿们常在交谈结束时说“73”，在CW电报语言中这代表什么意思？", ["再见 / 致以最美好的祝愿 (Best Regards)", "我的电没电了", "我生气了", "请安静"], "A", 2, "73是全球Ham界通用的美好道别用语。", ["无线电", "礼用语"]),
    (1, "在无网无信号的深山里，许多越野爱好者依赖哪种频率段的电磁波通过电离层反射实现跨省市甚至跨国的超远距离通联？", ["UHF极高频", "VHF超高频", "HF短波 (短波频段)", "5G信号"], "C", 2, "短波电台（HF）可以通过天波（电离层反射）实现跨国通联。", ["无线电", "短波"]),
    (1, "EDC圈子（Everyday Carry）核心崇尚的是什么文化？", ["每天背100公斤的东西健身", "挑选和搭配每天随身携带的小物件（如折刀、手电、战术笔、工具钳等），以备不时之需和生活美学", "每天带不同的宠物出门", "研究如何徒手劈砖"], "B", 1, "EDC爱好兼顾了男性的机械工具浪漫和日常实用主义。", ["EDC", "定义"]),
    (2, "EDC玩家背包中非常热门的“多功能工具钳（Multi-tool）”的两个最著名代表品牌是？", ["Leatherman (莱泽曼)", "Victorinox (维氏 / 瑞士军刀)", "Rolex (劳力士)", "Bvlgari (宝珀)"], "AB", 1, "莱泽曼和维氏瑞士军刀几乎垄断了高端民用多功能工具市场。", ["EDC", "工具钳"]),
    (1, "由于国内刀具管制非常严格，国内EDC玩家经常随身把玩的、且完全不带锋利刃口纯粹用来练手部动作的玩具刀被称为？", ["太刀", "蝴蝶刀(未开刃) / 甩刀 (Balisong trainer)", "菜刀", "指甲刀"], "B", 2, "蝴蝶梳、蝴蝶钝刀因其可以展现华丽的翻转技巧而受到年轻人欢迎。", ["EDC", "甩刀"]),
    (1, "EDC圈内玩家非常喜爱由钛合金、黄铜或锆合金等金属制成减压小玩具，下列属于此类减压玩具的是？", ["指尖陀螺", "金属推牌 / 啪啪币", "由于磁铁吸引而发出清脆声音的金属滚筒", "以上都是"], "D", 1, "这些都是EDC圈风靡的高溢价金属解压EDC玩具。", ["EDC", "解压玩具"]),
    (1, "在EDC高级小手电领域，“流明 (Lumen)”这个单位常用来衡量手电筒的什么指标？", ["电池容量", "光通量（通俗理解为亮度）", "重量", "射电频率"], "B", 1, "流明数越高，通常手电在宏观视觉上显得越亮。", ["EDC", "爆闪手电"]),

