    (1, "在竞技叠杯（Speed Stacks）运动中，最高殿堂级的循环花式（Cycle）总共由几个阶段的叠装和收杯组成？", ["1个阶段", "3个阶段 (3-6-3, 6-6, 1-10-1)", "5个", "10个"], "B", 2, "Cycle（花式循环）是杯子花式最多也最具观赏性的项目。", ["速叠杯", "Cycle"]),
    (1, "盲拧三阶魔方时，选手记忆使用的主要方法逻辑是将魔方的状态转化为？", ["数字死记硬背", "拼音或字母对，进而联想成中文词汇/故事宫殿", "颜色直接硬想", "求助场外指导"], "B", 2, "通过“字母对”转化成一个个具象的名词记忆法是现代盲拧的核心原理。", ["魔方", "盲拧"]),
    (1, "转笔中，连续不断地在手指间施展同一招式、形成永动机般无限循环连招的技巧统称为？", ["Aerial（抛空）", "Continuous (连转)", "Wiper", "Inf"], "B", 1, "Continuous（连转）由于视觉效果华丽，也是老手的重要考核指标之一。", ["转笔", "连招"]),
    (1, "速叠杯运动中，使用的杯子底部通常会有几个孔，这些孔的作用是？", ["为了省材料", "防止空气阻力，避免杯子粘在一起或空气排不出去，加快叠落速度", "为了漏水", "为了能看清对面"], "B", 1, "排气孔是专业竞技叠杯能以零点几秒极速收叠的物理学基础。", ["速叠杯", "硬件"]),
    (2, "下列哪些魔方属于WCA赛事的官方正式项目？", ["二阶魔方", "斜转 (Skewb)", "金字塔魔方 (Pyraminx)", "九百阶魔方"], "ABC", 1, "截至目前WCA未列入过高的超高阶魔方（目前最高只有普通赛里的7x7x7）。", ["魔方", "WCA"]),
    (1, "手指滑板（Fingerboard/滑板手指化）中，完成弹跳动作跳上台阶的最核心、最基础的招式是？", ["Ollie (豚跳)", "Kickflip", "Grind", "Grab"], "A", 2, "源自真实滑板，Ollie是利用后指点板让板面腾空飞起的地基招式。", ["手指滑板", "Ollie"]),
    
