    (1, "摄影中所谓的“曝光三要素”包括以下哪些？ (部分多选)", ["光圈", "快门速度", "焦距", "ISO（感光度）"], "ABD", 1, "光圈、快门速度、ISO共同决定了照片的最终曝光量。", ["摄影", "曝光三要素"]),
    (2, "机械键盘轴体中，经典的Cherry“青轴”和“红轴”的区别主要在于？", ["青轴有强烈的段落感和两段发声（Clicky声）", "红轴是直上直下没有手感顿挫的线性轴", "青轴必须插电才能用", "红轴专为打字设计，没有声音"], "AB", 1, "手感反馈（段落还是线性）是机械键盘核心的区别所在。", ["机械键盘", "轴体"]),
