    (1, "对于专业单反/微单摄影，照片存储为了后期极大空间，通常必须开启什么格式？", ["JPEG", "PNG", "RAW", "BMP"], "C", 1, "RAW记录了传感器原始数据，后期动态范围宽宽广无损。", ["摄影", "RAW格式"]),
    (1, "显示器参数中的“144Hz”或“240Hz”表示什么？", ["屏幕的颜色数量", "屏幕的刷新率 (每秒显示的画面帧数)", "显示器使用的电压", "显示器的厚度"], "B", 1, "Hz代表刷新率，数值越高高帧率游戏画面越流畅。", ["PC外设", "刷新率"]),
    (1, "在音频玄学中，Hi-Fi发烧友用来说明新耳机需要长时间播放来让振膜状态达到最佳的术语是？", ["热机", "煲机 (Burn-in)", "通电", "洗碟"], "B", 2, "煲机是指通过较长时间放音，使发声结构磨合。", ["HiFi", "听音观"]),
